        let currentLanguage = 'ar'; // أو 'en' حسب الافتراض

        // وظيفة لتبديل اللغة
        function toggleLanguage() {
            if (currentLanguage === 'ar') {
                currentLanguage = 'en';
                 document.getElementById('flagImage').src = 'ar.jpg'; // صورة علم العربية
                document.getElementById('flagImage').alt = 'العربية';
                document.getElementById('langText').innerText = 'عربي';
            } else {
                currentLanguage = 'ar';
               document.getElementById('flagImage').src = 'en.png'; // صورة علم الإنجليزية
                document.getElementById('flagImage').alt = 'English';
                document.getElementById('langText').innerText = 'English';
            }
            updateTexts(); // تحديث النصوص بناءً على اللغة الجديدة
        }

        // وظيفة لتحديث النصوص المترجمة
        function updateTexts() {
            document.querySelectorAll('[data-translate]').forEach(function(element) {
                const key = element.getAttribute('data-translate');
                if (translations[currentLanguage] && translations[currentLanguage][key]) {
            element.innerHTML = translations[currentLanguage][key];
                }
            });
        }

        // عند تحميل الصفحة، نحدث النصوص
        document.addEventListener('DOMContentLoaded', () => {
            updateTexts();
        });

